        self.capabilities_index
            .get(capability)
            .cloned()
            .unwrap_or_default()
    }

    /// Update tool index after discovery
    pub fn index_tools(&mut self, spoke_name: &str, tools: Vec<ToolDefinition>) {
        for tool in tools {
